// ScorePlay API Response parsen
// Erwartet: { data: [ { id, name, media_files: [...], event_id, ... } ] }
const items = $input.all();
const raw = items[0].json;

// Unterstütze beide Response-Formate: direkt als Array oder als { data: [...] }
const mediaList = Array.isArray(raw) ? raw : (raw.data || []);

const result = [];

for (const media of mediaList) {
  // URL-Felder aus media_files / details extrahieren
  const files = media.media_files || media.details || [];

  let thumbnail_url = null;
  let compressed_url = null;
  let original_url = null;

  for (const file of files) {
    const url = file.url || file.src || null;
    if (!url) continue;

    if (file.is_thumbnail === true) {
      thumbnail_url = url;
    } else if (file.is_compressed === true) {
      compressed_url = url;
    } else if (
      file.detail === 'photographer_quality' ||
      file.quality === 'photographer_quality'
    ) {
      original_url = url;
    }
  }

  // Fallback: erstes verfügbares URL als thumbnail
  if (!thumbnail_url && files.length > 0) {
    thumbnail_url = files[0].url || files[0].src || null;
  }

  result.push({
    json: {
      media_id: media.id,
      name: media.name || media.filename || null,
      thumbnail_url,
      compressed_url,
      original_url,
      event_id: media.event_id || media.eventId || null,
    }
  });
}

return result;
